sequential.groovy:
def string = ant.project.getProperty("thestring");
def targetProperty = ant.project.getProperty("theto");

def result = string.toLowerCase();

ant.project.setProperty(targetProperty,result);

def string = ant.project.getProperty("thestring");
def targetProperty = ant.project.getProperty("theto");

def result = string.toUpperCase();

ant.project.setProperty(targetProperty,result);

def string = ant.project.getProperty("thestring");
def pattern = ant.project.getProperty("thepattern");
def replacement = ant.project.getProperty("thereplacement");
def targetProperty = ant.project.getProperty("theto");

def result = string.replaceAll(pattern, replacement);

ant.project.setProperty(targetProperty,result);

def targetname = ant.project.getProperty("thetargetname");
def targetProperty = ant.project.getProperty("theproperty");

if(ant.project.getTargets().containsKey(targetname)) {
	ant.project.setProperty(targetProperty,"true");
}

def arg1 = ant.project.getProperty("arg1");
def arg2 = ant.project.getProperty("arg2");
def to = ant.project.getProperty("to");
def strict = ant.project.getProperty("strict");
def number1 = Integer.parseInt(arg1);
def number2 = Integer.parseInt(arg2);
def result = "false";
println(number1+"-"+number2+"-"+strict)
if (strict=="true") {
        if (number1 > number2) {
                result="true";
        }
} else {
        if (number1 >= number2 ) {
                result="true";
        }
}
ant.project.setProperty(to,result);
